	"sort"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	allowedBusinessSet := map[string]bool{
		"electronics": true,
		"grocery":      true,
		"pharmacy":     true,
		"restaurant":   true,
	}
	allowedBusiness := map[string]int{
		"electronics": 0,
		"grocery":      1,
		"pharmacy":     2,
		"restaurant":   3,
	}
	codeRegex := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	var validCoupons []struct {
		business string
		code     string
	}
	for i := 0; i < len(code); i++ {
		c := code[i]
		bl := businessLine[i]
		active := isActive[i]
		if c != "" && codeRegex.MatchString(c) && allowedBusinessSet[bl] && active {
			validCoupons = append(validCoupons, struct {
				business string
				code     string
			}{bl, c})
		}
	}
	sort.Slice(validCoupons, func(i, j int) bool {
		bl1 := validCoupons[i].business
		bl2 := validCoupons[j].business
		p1 := allowedBusiness[bl1]
		p2 := allowedBusiness[bl2]
		if p1 != p2 {
			return p1 < p2
		}
		return validCoupons[i].code < validCoupons[j].code
	})
	result := make([]string, len(validCoupons))
	for i := range validCoupons {
		result[i] = validCoupons[i].code
	}
	return result
}
