import (
	"regexp"
	"sort"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	allowedBusiness := map[string]bool{
		"electronics": true,
		"grocery":      true,
		"pharmacy":     true,
		"restaurant":   true,
	}
	allowedOrder := map[string]int{
		"electronics": 0,
		"grocery":      1,
		"pharmacy":     2,
		"restaurant":   3,
	}
	re := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	valid := []struct {
		BusinessLine string
		Code         string
	}{}
	for i := 0; i < len(code); i++ {
		c := code[i]
		bl := businessLine[i]
		active := isActive[i]
		if c == "" {
			continue
		}
		if !re.MatchString(c) {
			continue
		}
		if !allowedBusiness[bl] {
			continue
		}
		if !active {
			continue
		}
		valid = append(valid, struct {
			BusinessLine string
			Code         string
		}{bl, c})
	}
	sort.Slice(valid, func(i, j int) bool {
		a := valid[i]
		b := valid[j]
		aOrder := allowedOrder[a.BusinessLine]
		bOrder := allowedOrder[b.BusinessLine]
		if aOrder != bOrder {
			return aOrder < bOrder
		}
		return a.Code < b.Code
	})
	result := make([]string, len(valid))
	for i, v := range valid {
		result[i] = v.Code
	}
	return result
}
