import re

def solve(code: list[str], businessLine: list[str], isActive: list[bool]) -> list[str]:
    allowed_business = {"electronics", "grocery", "pharmacy", "restaurant"}
    order = {"electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3}
    pattern = re.compile(r'^[a-zA-Z0-9_]+$')
    valid_coupons = []
    for i in range(len(code)):
        c = code[i]
        bl = businessLine[i]
        active = isActive[i]
        if c and pattern.match(c) and bl in allowed_business and active:
            valid_coupons.append((bl, c))
    valid_coupons.sort(key=lambda x: (order[x[0]], x[1]))
    return [c for (bl, c) in valid_coupons]
